<?php
namespace Tests\Feature;use App\Models\{Checkin,Folio,FolioItem,FolioPayment,Guest,Reservation,Room,User};use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class FolioWorkflowTest extends TestCase{use RefreshDatabase;private function data(bool$active=false):array{$admin=User::factory()->create(['role'=>'manager']);$guest=Guest::create(['first_name'=>'Folio','last_name'=>'Guest','id_status'=>'verified']);$room=Room::create(['number'=>'901','type'=>'Suite','status'=>$active?'occupied':'available','price'=>200]);$r=Reservation::create(['guest_id'=>$guest->id,'room_id'=>$room->id,'reference'=>'RS-FOLIO','arrival_date'=>today()->subDay(),'departure_date'=>today()->addDays(2),'room_type'=>'Suite','status'=>$active?'checked_in':'confirmed']);$c=$active?Checkin::create(['reservation_id'=>$r->id,'guest_id'=>$guest->id,'room_id'=>$room->id,'check_in_date'=>today()->subDays(2),'check_out_date'=>today()->addDays(2),'booking_reference'=>$r->reference,'is_active'=>true]):null;return[$admin,$guest,$room,$r,$c];}
 public function test_reservation_folio_tracks_charges_payments_and_refunds():void{[$a,,,$r]=$this->data();$this->actingAs($a)->get(route('dashboard.bookings.folio',$r))->assertRedirect();$f=Folio::first();$this->actingAs($a)->post(route('dashboard.folios.items.store',$f),['type'=>'room_charge','description'=>'Night one','quantity'=>2,'unit_amount'=>100,'tax_amount'=>20,'service_date'=>today()->toDateString(),'notes'=>''])->assertSessionHasNoErrors();$this->assertSame('220.00',$f->fresh()->balance);$this->actingAs($a)->post(route('dashboard.folios.payments.store',$f),['method'=>'cash','amount'=>220,'provider'=>'','external_reference'=>'CASH-1','notes'=>'Paid at desk'])->assertSessionHasNoErrors();$this->assertSame('settled',$f->fresh()->status);$payment=FolioPayment::where('type','payment')->first();$this->actingAs($a)->post(route('dashboard.folios.refunds.store',$f),['parent_payment_id'=>$payment->id,'method'=>'cash','amount'=>50,'provider'=>'','external_reference'=>'','notes'=>'Approved adjustment'])->assertSessionHasNoErrors();$this->assertSame('50.00',$f->fresh()->balance);}
 public function test_manager_can_void_charge_and_front_desk_cannot_refund():void{[$a,,,$r]=$this->data();$f=Folio::forReservation($r);$item=FolioItem::create(['folio_id'=>$f->id,'type'=>'damage','description'=>'Lamp','quantity'=>1,'unit_amount'=>80,'tax_amount'=>0,'total_amount'=>80,'service_date'=>today()]);$front=User::factory()->create(['role'=>'front_desk']);$this->actingAs($front)->patch(route('dashboard.folio-items.void',$item),['reason'=>'Mistake'])->assertForbidden();$this->actingAs($a)->patch(route('dashboard.folio-items.void',$item),['reason'=>'Posted to wrong guest'])->assertSessionHasNoErrors();$this->assertTrue($item->fresh()->voided);}
 public function test_nightly_posting_is_idempotent():void{[$a,,,$r,$c]=$this->data(true);$date=today()->subDay()->toDateString();$this->artisan('folios:post-nightly',[$date])->assertSuccessful();$this->artisan('folios:post-nightly',[$date])->assertSuccessful();$f=Folio::where('reservation_id',$r->id)->first();$this->assertNotNull($f);$this->assertSame(1,$f->items()->where('type','room_charge')->count());$this->assertSame('200.00',$f->fresh()->balance);}
 public function test_no_show_fee_posts_to_folio():void{[$a,,,$r]=$this->data();$this->actingAs($a)->patch(route('dashboard.bookings.no-show',$r),['fee'=>125,'reason'=>'Did not arrive'])->assertSessionHasNoErrors();$f=Folio::where('reservation_id',$r->id)->first();$this->assertSame('125.00',$f->balance);$this->assertDatabaseHas('folio_items',['folio_id'=>$f->id,'type'=>'no_show','total_amount'=>125]);}
}
